mapper.select:
-- 方式一：获取用户直接关联的角色 SELECT r.role_code FROM sys_role r INNER JOIN sys_user_role ur ON r.id = ur.role_id WHERE ur.user_id = #{userId,jdbcType=BIGINT} AND r.disable = 0
UNION
-- 方式二：获取用户所在用户组绑定的角色 SELECT r.role_code FROM sys_role r INNER JOIN sys_user_group_role ugr ON r.id = ugr.role_id INNER JOIN sys_user_group_user ugu ON ugr.group_id = ugu.group_id INNER JOIN sys_user_group ug ON ug.id = ugu.group_id WHERE ugu.user_id = #{userId,jdbcType=BIGINT} AND r.disable = 0 AND ug.disable = 0;
